      "content": "const { randomUUID } = require('../../lib/id');
const members = [];

const createMember = (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'User ID and role are required' } });
  const member = { id: randomUUID(), userId, role };
  members.push(member);
  res.status(201).json({ member });
};

const getMembers = (req, res) => {
  res.json({ members });
};

module.exports = { createMember, getMembers };
